package be.schaubroeck.lpb.rkm.rekenmotor.results;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.PersoonIdOpdrachNrDatumKey;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.RegulAgendaKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenFeedback;
import be.schaubroeck.lpb.rkm.rekenmotor.util.TimeTools;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.RegulAgenda;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.jpa.lo.RegulAgendaPK;
import be.schaubroeck.lpb.tools.jpa.lo.RegulAgendaPO;
import be.schaubroeck.lpb.tools.service.RegulAgendaService;
import be.schaubroeck.lpb.tools.service.WachtAgendaService;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import com.google.common.collect.ArrayListMultimap;
import com.google.common.collect.ListMultimap;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.OPSLAAN_NULRESULTATEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REGUL_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKEN_FEEDBACK_KEY;

public abstract class AbstractResultaatHandler implements ResultaatHandler {

    protected static final boolean SUCCES = false;

    protected Integer rekenBatchNr;

    private RegulAgendaService regulAgendaService;
    private WachtAgendaService wachtAgendaService;

    public AbstractResultaatHandler(RegulAgendaService regulAgendaService, WachtAgendaService wachtAgendaService) {
        this.regulAgendaService = regulAgendaService;
        this.wachtAgendaService = wachtAgendaService;
    }

    protected boolean opslaanNulResultaten(RekenContext mainContext) {
        Integer opslaanNulresultaten = mainContext.getInteger(OPSLAAN_NULRESULTATEN_KEY);
        return opslaanNulresultaten == 1;
    }

    @Override
    public void verwerkReguls(Admin admin, RekenContext mainContext, boolean stopState) {
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        RegulManager regulManager = mainContext.getUnchecked(REGUL_MANAGER_KEY);
        List<RegulAgenda> regulAgenda = behandelRegulAgenda(regulManager);

        if (stopState == SUCCES) {
            ListMultimap<RegulAgendaKey, RegulAgenda> nieuweRegulsMap = ArrayListMultimap.create();
            regulAgenda.forEach(x -> nieuweRegulsMap.put(new RegulAgendaKey(x), x));
            Set<Integer> opdrachtNrs = persoon.getOpdrachten().stream().map(Opdracht::getOpdrachtnr).collect(Collectors.toSet());
            List<RegulAgenda> bestaanden = regulAgendaService.findByPersoonIdAndDatum(admin, rekenTijd.rekenPeriode, persoon.getId(), opdrachtNrs);
            for (RegulAgenda agenda : bestaanden) {
                if (agenda.getBeginDatum().getMonthOfYear() != agenda.getEindDatum().getMonthOfYear() || agenda.getBeginDatum().getYear() != agenda
                        .getEindDatum().getYear()) {
                    List<RegulAgenda> lijst = nieuweRegulsMap.get(new RegulAgendaKey(agenda));
                    LocalDateInterval splitPeriode = lijst.stream().map(RegulAgenda::getPeriode).reduce(rekenTijd.rekenPeriode, TimeTools::union);
                    split(admin, agenda, splitPeriode);
                } else {
                    regulAgendaService.delete(admin, agenda);
                }
            }
        }

        regulAgendaService.create(admin, regulAgenda);
        RekenFeedback feedback = mainContext.getUnchecked(REKEN_FEEDBACK_KEY);
        if (feedback != null) {
            feedback.setAantalRegulAgendas(regulAgenda.size());
        }
    }

    private void split(Admin admin, RegulAgenda regulAgenda, LocalDateInterval splitPeriode) {
        LocalDateInterval periode = regulAgenda.getPeriode();
        List<RegulAgenda> toCreate = new ArrayList<>();
        if (periode.overlaps(splitPeriode)) {
            if (periode.getStart().compareTo(splitPeriode.getStart()) < 0) {
                RegulAgenda before = maakCopy(regulAgenda);
                before.setEindDatum(splitPeriode.getStart().minusDays(1));
                toCreate.add(before);
            }
            if (periode.getEnd().compareTo(splitPeriode.getEnd()) > 0) {
                RegulAgenda after = maakCopy(regulAgenda);
                after.setBeginDatum(splitPeriode.getEnd().plusDays(1));
                toCreate.add(after);
            }
        }
        regulAgendaService.delete(admin, regulAgenda);
        regulAgendaService.create(admin, toCreate);
    }

    private RegulAgenda maakCopy(RegulAgenda regulAgenda) {
        RegulAgenda regul = new RegulAgendaPO();
        RegulAgendaPK id = new RegulAgendaPK();
        regul.setId(id);
        regul.setBeginDatum(regulAgenda.getBeginDatum());
        regul.setEindDatum(regulAgenda.getEindDatum());
        regul.setWerkgever(regulAgenda.getWerkgever());
        regul.setPersoon(regulAgenda.getPersoon());
        regul.setOpdrachtNummer(regulAgenda.getOpdrachtNummer());
        regul.setRegulStatus(regulAgenda.getRegulStatus());
        regul.setRekenBatchNr(regulAgenda.getRekenBatchNr());
        regul.setBron(regulAgenda.getBron());
        return regul;
    }

    private List<RegulAgenda> behandelRegulAgenda(RegulManager regulManager) {
        List<RegulAgenda> regulAgenda = regulManager.getRegulAgenda();
        regulAgenda = filterOpOverbodigeFoutAnderOpdrachtReguls(regulAgenda);
        if (rekenBatchNr != null) {
            regulAgenda.forEach(x -> x.setRekenBatchNr(rekenBatchNr));
        }
        return regulAgenda;
    }

    private List<RegulAgenda> filterOpOverbodigeFoutAnderOpdrachtReguls(List<RegulAgenda> regulAgenda) {
        Set<PersoonIdOpdrachNrDatumKey> agendaKeys = new HashSet<>();
        List<RegulAgenda> normaleAgenda = new ArrayList<>();
        List<RegulAgenda> dummyAgenda = new ArrayList<>();
        for (RegulAgenda punt : regulAgenda) {
            if (punt.getRegulStatus().equals(Regulkode.FOUT_ANDERE_OPDRACHT.getCode())) {
                dummyAgenda.add(punt);
            } else {
                normaleAgenda.add(punt);
                agendaKeys.add(new PersoonIdOpdrachNrDatumKey(punt.getPersoon().getId(), punt.getOpdrachtNummer(), punt.getBeginDatum()));
            }
        }
        for (RegulAgenda punt : dummyAgenda) {
            PersoonIdOpdrachNrDatumKey key =
                    new PersoonIdOpdrachNrDatumKey(punt.getPersoon().getId(), punt.getOpdrachtNummer(), punt.getBeginDatum());
            if (!agendaKeys.contains(key)) {
                normaleAgenda.add(punt);
            }
        }

        return normaleAgenda;

    }

    @Override
    public boolean isTeNegeren(Admin admin, org.joda.time.LocalDate datum, Persoon persoon) {
        return wachtAgendaService.checkWachtAgendaExists(admin, datum, persoon.getId());
    }

    @Override
    public Integer getRekenBatchNr() {
        return rekenBatchNr;
    }

    @Override
    public void setRekenBatchNr(Integer rekenBatchNr) {
        this.rekenBatchNr = rekenBatchNr;
    }
}
